import{_ as a,o as i,c as l,a2 as e}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"可见性、可供性、意符、反馈、一致性与约束","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/01-principles/02-visibility-affordance-feedback-consistency-constraints.md","filePath":"03-interaction-design/notes/01-principles/02-visibility-affordance-feedback-consistency-constraints.md","lastUpdated":1784542968000}'),d={name:"03-interaction-design/notes/01-principles/02-visibility-affordance-feedback-consistency-constraints.md"};function r(n,t,s,h,o,c){return i(),l("div",null,[...t[0]||(t[0]=[e(`<h1 id="可见性、可供性、意符、反馈、一致性与约束" tabindex="-1">可见性、可供性、意符、反馈、一致性与约束 <a class="header-anchor" href="#可见性、可供性、意符、反馈、一致性与约束" aria-label="Permalink to &quot;可见性、可供性、意符、反馈、一致性与约束&quot;">​</a></h1><p>这组原则共同回答：用户能否发现可执行动作、判断怎样操作、理解系统结果，并避免进入无效状态。它们不是视觉风格规则，而是连接用户意图与系统状态的交互机制。</p><h2 id="概念边界" tabindex="-1">概念边界 <a class="header-anchor" href="#概念边界" aria-label="Permalink to &quot;概念边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>解决的问题</th><th>设计对象</th><th>失败表现</th></tr></thead><tbody><tr><td>可见性</td><td>当前有哪些状态与动作可被感知？</td><td>操作入口、状态、进度、结果</td><td>功能存在但找不到，状态变化无从判断</td></tr><tr><td>可供性</td><td>对象实际允许什么行为？</td><td>控件与平台能力</td><td>看似可拖动但实际不能拖动</td></tr><tr><td>意符</td><td>什么线索表明可供性存在？</td><td>标签、形状、位置、光标、边界、图标</td><td>纯文字按钮与正文无法区分</td></tr><tr><td>反馈</td><td>系统是否收到动作，结果是什么？</td><td>控件、区域、状态消息、结果页</td><td>重复点击、误以为成功或失败</td></tr><tr><td>一致性</td><td>相同概念和功能是否可预测？</td><td>名称、结构、行为、键盘模式</td><td>同名不同义、同功能不同操作</td></tr><tr><td>约束</td><td>怎样限制不合法动作或状态？</td><td>数据规则、权限、控件和流程</td><td>用户完成大量输入后才发现不能提交</td></tr></tbody></table><p>可供性与意符不能混用：按钮具有触发动作的可供性，边框、标签和按下状态是让用户感知这种能力的意符。视觉上像按钮但没有动作，是错误意符；无标签的图标按钮可能有真实能力，但意符不足。</p><h2 id="协作机制" tabindex="-1">协作机制 <a class="header-anchor" href="#协作机制" aria-label="Permalink to &quot;协作机制&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G[&quot;用户目标&quot;] --&gt; V[&quot;看见状态与可用动作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    V --&gt; S[&quot;意符提示操作方式&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; A[&quot;执行动作&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; C[&quot;约束检查合法性&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|合法| F[&quot;反馈结果与新状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|不合法| E[&quot;说明原因与修正方式&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; V</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>一致性贯穿整个循环：相同功能的名称、语义、结果和键盘操作保持可预测；当业务状态确实不同，差异应明确表达，而不是为了表面统一隐藏规则。</p><h2 id="可见性" tabindex="-1">可见性 <a class="header-anchor" href="#可见性" aria-label="Permalink to &quot;可见性&quot;">​</a></h2><p>可见性包括视觉可见、键盘可达和辅助技术可感知。一个状态只在屏幕上改变颜色，不代表所有用户都能获知。</p><h3 id="需要可见的信息" tabindex="-1">需要可见的信息 <a class="header-anchor" href="#需要可见的信息" aria-label="Permalink to &quot;需要可见的信息&quot;">​</a></h3><ul><li>当前对象、位置与状态；</li><li>主要操作及其作用对象；</li><li>系统是否正在处理、是否保存、是否离线；</li><li>权限、限制和必要前置条件；</li><li>操作结果、错误与恢复方式。</li></ul><p>可见不等于所有功能永久展开。低频操作可以放入可发现菜单，但入口、菜单名称和打开方式必须可靠；危险操作可以降低视觉权重，不能隐藏到用户无法完成合法任务。</p><h2 id="可供性与意符" tabindex="-1">可供性与意符 <a class="header-anchor" href="#可供性与意符" aria-label="Permalink to &quot;可供性与意符&quot;">​</a></h2><h3 id="常见意符" tabindex="-1">常见意符 <a class="header-anchor" href="#常见意符" aria-label="Permalink to &quot;常见意符&quot;">​</a></h3><ul><li>可见文字标签和动作动词；</li><li>控件边界、填充、大小和位置；</li><li>链接的文本样式与访问状态；</li><li>拖动手柄、调整光标和可放置区域；</li><li>展开图标及程序化展开状态；</li><li>焦点指示和按下、选中状态。</li></ul><p>悬停样式不能作为唯一意符，因为触屏没有稳定悬停，键盘用户依赖焦点。图标也不应成为陌生或关键动作的唯一名称；可见标签与可访问名称应一致或至少包含相同文本。</p><h2 id="反馈" tabindex="-1">反馈 <a class="header-anchor" href="#反馈" aria-label="Permalink to &quot;反馈&quot;">​</a></h2><p>反馈应与动作风险、等待时间和结果持久性匹配。</p><table tabindex="0"><thead><tr><th>情况</th><th>合适反馈</th><th>不足反馈</th></tr></thead><tbody><tr><td>开关切换</td><td>控件状态立即改变，持久化失败时恢复并说明</td><td>只出现“完成”Toast</td></tr><tr><td>搜索刷新</td><td>显示加载与结果数，保持输入和焦点</td><td>整页闪烁但不说明结果</td></tr><tr><td>文件处理</td><td>区分上传进度与服务端处理状态</td><td>上传到 100% 就显示最终成功</td></tr><tr><td>删除数据</td><td>明确对象、结果和撤销或恢复条件</td><td>无对象名的“操作成功”</td></tr><tr><td>表单错误</td><td>错误摘要、字段错误和修正建议</td><td>只把边框改红</td></tr></tbody></table><p>动态反馈若不移动焦点，应使用适当语义让辅助技术获知。非紧急结果通常不应使用持续打断的 assertive live region。</p><h2 id="一致性" tabindex="-1">一致性 <a class="header-anchor" href="#一致性" aria-label="Permalink to &quot;一致性&quot;">​</a></h2><h3 id="内部一致性" tabindex="-1">内部一致性 <a class="header-anchor" href="#内部一致性" aria-label="Permalink to &quot;内部一致性&quot;">​</a></h3><p>产品内相同对象、动作、图标、状态和键盘操作保持一致。例如“归档”在所有位置都保留对象并从默认列表移除，不能在另一个页面实际永久删除。</p><h3 id="平台一致性" tabindex="-1">平台一致性 <a class="header-anchor" href="#平台一致性" aria-label="Permalink to &quot;平台一致性&quot;">​</a></h3><p>优先使用平台已有语义和键盘约定：链接导航，按钮执行动作，Tab 移动焦点，Space/Enter 按对应原生控件行为操作。自定义组件若偏离约定，需要更高学习和实现成本。</p><h3 id="任务一致性" tabindex="-1">任务一致性 <a class="header-anchor" href="#任务一致性" aria-label="Permalink to &quot;任务一致性&quot;">​</a></h3><p>一致不是机械复制。如果移动端空间、风险或对象状态改变，布局和步骤可以不同，但任务结果、术语与关键规则应保持一致。</p><h2 id="约束" tabindex="-1">约束 <a class="header-anchor" href="#约束" aria-label="Permalink to &quot;约束&quot;">​</a></h2><p>约束可以按实施层次分类：</p><ul><li><strong>物理或平台约束</strong>：控件只接受可支持的输入方式。</li><li><strong>语义约束</strong>：日期结束值必须晚于开始值。</li><li><strong>业务约束</strong>：已发货订单不能修改配送地址。</li><li><strong>权限约束</strong>：查看者不能删除项目。</li><li><strong>流程约束</strong>：高风险提交前需要复核。</li></ul><h3 id="隐藏、禁用、只读与允许后解释" tabindex="-1">隐藏、禁用、只读与允许后解释 <a class="header-anchor" href="#隐藏、禁用、只读与允许后解释" aria-label="Permalink to &quot;隐藏、禁用、只读与允许后解释&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>何时使用</th><th>风险</th></tr></thead><tbody><tr><td>隐藏</td><td>操作与当前角色完全无关，暴露会增加噪声或安全风险</td><td>用户不知道功能存在及如何获得权限</td></tr><tr><td>禁用</td><td>操作暂时不可用，且用户需要看见顺序或条件</td><td>原因不可发现，键盘可能无法聚焦说明</td></tr><tr><td>只读</td><td>内容可查看复制，但不能修改</td><td>外观若与可编辑相同会误导</td></tr><tr><td>允许进入后解释</td><td>用户需要理解规则、申请权限或完成前置条件</td><td>过晚阻止会浪费输入</td></tr></tbody></table><p>禁用不是完整解释。可在控件附近显示前置条件，或使用可聚焦说明元素。不要依赖禁用控件的 tooltip，因为禁用原生控件通常不能获得键盘焦点。</p><h2 id="完整案例-发布文章" tabindex="-1">完整案例：发布文章 <a class="header-anchor" href="#完整案例-发布文章" aria-label="Permalink to &quot;完整案例：发布文章&quot;">​</a></h2><h3 id="状态与操作" tabindex="-1">状态与操作 <a class="header-anchor" href="#状态与操作" aria-label="Permalink to &quot;状态与操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文章状态</th><th>主要操作</th><th>约束</th><th>反馈</th></tr></thead><tbody><tr><td>空草稿</td><td>添加内容</td><td>标题和正文为空不能发布</td><td>就地说明必要内容</td></tr><tr><td>可发布草稿</td><td>发布</td><td>需要发布权限</td><td>按钮名称明确，提交前显示影响范围</td></tr><tr><td>发布中</td><td>无重复发布</td><td>请求未完成</td><td>忙碌状态、保留对象名、允许安全离开时说明</td></tr><tr><td>已发布</td><td>查看、创建新版本</td><td>当前版本不可直接覆盖</td><td>显示发布时间和公开链接</td></tr><tr><td>发布失败</td><td>重试或返回编辑</td><td>输入保持不变</td><td>说明是否有任何内容已公开</td></tr></tbody></table><h3 id="行为设计" tabindex="-1">行为设计 <a class="header-anchor" href="#行为设计" aria-label="Permalink to &quot;行为设计&quot;">​</a></h3><ol><li>页面标题和状态标签显示当前文章与“草稿”。</li><li>“发布”是可见文字按钮；无权限时不只置灰，在操作区说明“需要编辑者权限”及申请方式。</li><li>缺少标题时，操作前即可看见要求；提交后错误摘要与标题字段关联。</li><li>进入发布中后按钮显示明确忙碌状态，防止重复请求。</li><li>成功进入持久结果，显示公开 URL、版本和下一步；通过状态消息宣布动态更新。</li><li>失败保留内容，区分可重试网络错误与需要修改内容的规则错误。</li></ol><h3 id="键盘与辅助技术" tabindex="-1">键盘与辅助技术 <a class="header-anchor" href="#键盘与辅助技术" aria-label="Permalink to &quot;键盘与辅助技术&quot;">​</a></h3><ul><li>发布按钮使用原生按钮语义，焦点可见。</li><li>页面结构变化不改变自然焦点顺序；聚焦控件不会自动提交。</li><li>文章状态、字段错误和发布结果不只靠颜色表达。</li><li>对话框若用于最终确认，打开、Tab、Escape 和关闭后的焦点遵循对话框模式。</li></ul><h2 id="可执行设计步骤" tabindex="-1">可执行设计步骤 <a class="header-anchor" href="#可执行设计步骤" aria-label="Permalink to &quot;可执行设计步骤&quot;">​</a></h2><ol><li>列出任务每一步用户必须看见的对象、状态和操作。</li><li>为每个可执行对象写真实可供性和对应意符。</li><li>记录动作发生后立即、处理中和结束时的反馈。</li><li>检查相同功能在名称、位置、结果与键盘行为上的一致性。</li><li>列出业务、权限、数据与流程约束，决定提前解释方式。</li><li>为隐藏、禁用、只读和允许后解释分别写选择理由。</li><li>补齐成功、失败、取消、离线和并发状态。</li><li>用键盘、触屏、屏幕阅读器和不同视觉条件验证。</li></ol><h2 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h2><ul><li>把“看得见”仅理解为视觉显示，忽略键盘与辅助技术。</li><li>用悬停作为唯一操作提示或说明渠道。</li><li>图标外观像按钮，实际点击区域、键盘语义或名称缺失。</li><li>所有异步结果都用同一种 Toast，不区分持久性与风险。</li><li>为保持一致而保留不适合当前任务的交互。</li><li>禁用操作却不说明原因和恢复条件。</li><li>只在前端约束输入，服务端没有权威校验。</li><li>错误只用红色表示，未用文本描述问题。</li></ul><h2 id="验证步骤" tabindex="-1">验证步骤 <a class="header-anchor" href="#验证步骤" aria-label="Permalink to &quot;验证步骤&quot;">​</a></h2><ol><li>隐去视觉样式，只看语义结构和文本，确认操作仍可识别。</li><li>仅用键盘完成任务，检查焦点、激活方式和动态反馈。</li><li>用屏幕阅读器核对名称、角色、值、展开状态、错误和结果。</li><li>在触屏上检查没有悬停时是否仍能发现与操作。</li><li>制造权限不足、规则不满足、请求慢、失败和重复提交。</li><li>搜索相同功能在不同页面的名称和结果，修复不一致后复测。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>审计一个“创建团队”表单，产出原则检查表和修改方案。</p><p>完成时应满足：</p><ul><li>每个操作都有真实可供性与至少一个可靠意符；</li><li>必要状态和限制在用户行动前可见；</li><li>提交、等待、成功和失败都有与风险匹配的反馈；</li><li>相同功能的可见名称、可访问名称和行为一致；</li><li>权限、字段和业务约束说明隐藏、禁用或阻止的理由；</li><li>键盘、触屏和屏幕阅读器均可完成；</li><li>错误可定位、可理解、可修正且输入不丢失。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.w3.org/TR/WCAG22/" target="_blank" rel="noreferrer">W3C：Web Content Accessibility Guidelines (WCAG) 2.2</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/consistent-identification.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 3.2.4 Consistent Identification</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/error-identification.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 3.3.1 Error Identification</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/WCAG22/Understanding/status-messages.html" target="_blank" rel="noreferrer">W3C WAI：Understanding SC 4.1.3 Status Messages</a>（访问日期：2026-07-17）</li></ul>`,53)])])}const u=a(d,[["render",r]]);export{b as __pageData,u as default};
